import{_ as e,o as a,c as i,ag as l}from"./chunks/framework-C5-Jzrz4.js";const o=JSON.parse('{"title":"文档治理分析","description":"docs/scripts 与当前源码一致性的分析结论","frontmatter":{"title":"文档治理分析","description":"docs/scripts 与当前源码一致性的分析结论","lastUpdated":true},"headers":[],"relativePath":"scripts/analysis/文档治理分析.md","filePath":"scripts/analysis/文档治理分析.md","lastUpdated":null}');const d=e({name:"scripts/analysis/文档治理分析.md"},[["render",function(e,o,d,c,r,t){return a(),i("div",null,[...o[0]||(o[0]=[l('<h1 id="文档治理分析" tabindex="-1">文档治理分析 <a class="header-anchor" href="#文档治理分析" aria-label="Permalink to &quot;文档治理分析&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>本文档记录 <code>docs/scripts</code> 在本次整理中的一致性分析结论，目标是让文档与源码保持同步且可维护。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>文档治理</li><li>文档与源码一致性复核</li><li>新增文档前的结构判断</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>apps/web-antd/src</code></li><li><code>packages/*</code></li><li><code>internal/*</code></li><li><code>docs/scripts/*</code></li><li><code>docs/.vitepress/config.mts</code></li></ul><h2 id="核心机制或功能说明" tabindex="-1">核心机制或功能说明 <a class="header-anchor" href="#核心机制或功能说明" aria-label="Permalink to &quot;核心机制或功能说明&quot;">​</a></h2><h3 id="盘点结论-本轮" tabindex="-1">盘点结论（本轮） <a class="header-anchor" href="#盘点结论-本轮" aria-label="Permalink to &quot;盘点结论（本轮）&quot;">​</a></h3><ul><li><code>guide</code>：已按启动、路由、状态、HTTP、i18n、偏好配置重写</li><li><code>api</code>：从单页大文档拆分为请求封装/模块组织/核心接口</li><li><code>components</code>：按包能力与应用层组件分离，避免把工具包写成组件</li><li><code>analysis</code>：保留结构化分析，去除模板化泛文</li><li><code>development/deployment/maintenance/reference</code>：改为可执行目录化文档</li></ul><h3 id="一致性风险点" tabindex="-1">一致性风险点 <a class="header-anchor" href="#一致性风险点" aria-label="Permalink to &quot;一致性风险点&quot;">​</a></h3><ul><li>根导出 <code>#/api</code> 仅包含 <code>core</code>，历史文档常误写为“导出全部 API”</li><li><code>system/dict</code> 当前没有 <code>index.ts</code>，只能按文件导入</li><li>组件文档中旧的演示占位写法（如 <code>DemoPreview</code>）与当前站点内容无直接对应</li></ul><h3 id="文档治理原则" tabindex="-1">文档治理原则 <a class="header-anchor" href="#文档治理原则" aria-label="Permalink to &quot;文档治理原则&quot;">​</a></h3><ul><li>以导出入口和实现代码为准，不以历史描述为准</li><li>同类信息单点维护，避免多文档互相矛盾</li><li>文档新增后必须同步 <code>vitepress</code> 配置与 <code>reference/文档目录.md</code></li></ul><h2 id="使用方式、扩展方式或注意事项" tabindex="-1">使用方式、扩展方式或注意事项 <a class="header-anchor" href="#使用方式、扩展方式或注意事项" aria-label="Permalink to &quot;使用方式、扩展方式或注意事项&quot;">​</a></h2><ul><li>发现文档不一致时，先定位对应源码文件，再修正文档，不做“经验补写”。</li><li>若结构变化较大，优先改 <code>reference</code> 与导航入口，再分批改正文。</li><li>对尚无稳定导出的能力，文档应明确标注“以实际实现为准”。</li></ul>',16)])])}]]);export{o as __pageData,d as default};
